import React, { Component } from 'react';
import { withRouter } from 'react-router-dom';

import BlogPostStore from '../stores/BlogPostStore';

import ReactMarkdown from 'react-markdown';

class BlogPost extends Component {
  constructor() {
    super();

    this.state = {
      source: null
    };
  }

  getLatest = () => BlogPostStore.getLatest().then(post => this.setState({ post: post }));

  getPost = title =>
    BlogPostStore.getPostByTitle(title).then(post => {
      if (post) this.setState({ post: post });
      // else this.getLatest();
    });

  componentDidMount() {
    if (this.props.latest) return this.getLatest();

    if (this.props.match && this.props.match.params && this.props.match.params.title)
      return this.getPost(this.props.match.params.title);
  }

  componentDidUpdate(prevProps) {
    if (this.props.match.path === '/' && prevProps.match.path !== '/')
      return this.getLatest();
    if (this.props.match.params.title !== prevProps.match.params.title)
      return this.getPost(this.props.match.params.title);
  }

  render() {
    return (
      <div className="blog-post">
        <ReactMarkdown source={this.props.source || this.state.post} />
      </div>
    );
  }
}

export default withRouter(BlogPost);



