import React, { Component } from 'react';
import { Link, withRouter } from 'react-router-dom';

import BlogPostStore from '../stores/BlogPostStore';

class BlogPostExplorer extends Component {
  constructor() {
    super();

    this.state = { posts: null };
  }

  componentDidMount() {
    BlogPostStore.listPosts().then(posts => this.setState({ posts: posts }));
  }

  render() {
    if (this.state.posts === null) return <div />;
    const list = this.state.posts.map((post, i) => (
      <li key={i}>
        <Link to={`/blog/${post.title}`}>{post.title}</Link>
      </li>
    ));
    return (
      <div className="blog-explorer">
        <p>Blog Posts</p>
        <ul>{list}</ul>
      </div>
    );
  }
}

export default withRouter(BlogPostExplorer);



