import React, { Component } from 'react';
import { BrowserRouter as Router, Route, Switch, Link } from 'react-router-dom';

import AboutContent from './components/AboutContent';
import BlogPosts from './components/BlogPosts.js';
import BlogPost from './components/BlogPost';
import BlogPostExplorer from './components/BlogPostExplorer';
import Links from './components/Links';
import LinkStore from './stores/LinkStore';

import './styles/App.css';

class App extends Component {
  render() {
    return (
      <Router basename={process.env.PUBLIC_URL}>
        <div className="site">
          <header>
            <Link to="/">
              <img
                src="https://secure.gravatar.com/avatar/c4e709bd57dc17bd5723fece28bfa0ea?s=250"
                className="logo"
                alt="logo"
              />
            </Link>
            <AboutContent />
            <Links links={LinkStore} />
          </header>
          <div className="content">
            <BlogPostExplorer />
            <Switch>
              <Route
                exact
                path="/blog/latest"
                render={() => <BlogPost latest={true} />}
              />
              <Route path="/blog/:title" component={BlogPost} />
              <Route exact path="/blog" component={BlogPosts} />
              <Route render={() => <BlogPost latest={true} />} />
            </Switch>
          </div>
        </div>
      </Router>
    );
  }
}

export default App;



