class BlogPostStore {
  static getPostPaths = () =>
    require
      .context('../../public/blog-posts', true, /\.md$/)
      .keys()
      .map(x => x.replace('./', '../blog-posts/'));

  static getPostByPath = async path => {
    const res = await fetch(path);
    const text = await res.text();
    return await Promise.resolve(text);
  };

  static getPostByTitle = async title => {
    const post = BlogPostStore.getPostPaths().find(post => post.includes(title));
    if (!post) return;
    const res = await fetch(post);
    const text = await res.text();
    return await Promise.resolve(text);
  };

  static getAll = async () =>
    await Promise.all(
      BlogPostStore.getPostPaths()
        .map(post => BlogPostStore.getPostByPath(post))
        .reverse()
    );

  static getLatest = async () => {
    const latest = BlogPostStore.getPostPaths().reverse()[0];
    const post = await BlogPostStore.getPostByPath(latest);
    return await Promise.resolve(post);
  };

  static listPosts = async () => {
    const posts = await BlogPostStore.getPostPaths();

    return posts
      .map(post => ({
        location: post,
        title: post.replace('../blog-posts/', '').replace('.md', '')
      }))
      .reverse();
  };
}

export default BlogPostStore;



